// src/pages/PracticePage.js
import React, { useState } from "react";
import { useRecorder } from "../utils/useRecorder";
import "./PracticePage.css";

const SCENARIOS = [
  { id: "thesis",    label: "Thesis Defense",   emoji: "🎓", hint: "Practice defending your research clearly and confidently." },
  { id: "interview", label: "Job Interview",    emoji: "💼", hint: "Ace your next interview with confident, clear answers." },
  { id: "recitation",label: "Recitation",       emoji: "📖", hint: "Practice reciting passages or poems with good pacing." },
  { id: "general",   label: "General Speaking", emoji: "🎤", hint: "Free-form practice for any speaking situation." },
];

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function PracticePage({ navigate }) {
  const [scenario, setScenario] = useState(null);
  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState("");
  const { isRecording, audioBlob, audioMime, duration, elapsed, error, startRecording, stopRecording, getExtension } = useRecorder();

  const fmt = (s) => `${Math.floor(s / 60).toString().padStart(2, "0")}:${(s % 60).toString().padStart(2, "0")}`;

  const handleAnalyze = async () => {
    if (!audioBlob || !scenario) return;
    setLoading(true);

    const messages = [
      "Uploading your recording…",
      "Transcribing with Whisper…",
      "Analyzing speech patterns…",
      "Generating AI coaching…",
    ];
    let msgIdx = 0;
    setLoadingMsg(messages[0]);
    const msgInterval = setInterval(() => {
      msgIdx = (msgIdx + 1) % messages.length;
      setLoadingMsg(messages[msgIdx]);
    }, 2200);

    try {
      const formData = new FormData();
      const ext = getExtension ? getExtension() : "webm";
      formData.append("audio", audioBlob, `recording.${ext}`);
      formData.append("scenario", scenario.label);
      formData.append("duration", duration.toString());

      const res = await fetch(`${API_URL}/api/analyze`, { method: "POST", body: formData });
      if (!res.ok) throw new Error("Analysis failed. Please try again.");
      const data = await res.json();
      clearInterval(msgInterval);
      navigate("results", data);
    } catch (err) {
      clearInterval(msgInterval);
      setLoading(false);
      alert(err.message);
    }
  };

  // ── LOADING STATE ──────────────────────────────────
  if (loading) {
    return (
      <div className="practice-page center">
        <div className="loading-box">
          <div className="spinner" />
          <p className="loading-msg">{loadingMsg}</p>
          <p className="loading-sub">Hang tight — this takes about 10–20 seconds</p>
        </div>
      </div>
    );
  }

  // ── SCENARIO SELECTION ─────────────────────────────
  if (!scenario) {
    return (
      <div className="practice-page">
        <nav className="navbar">
          <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
          <button className="btn btn-ghost" onClick={() => navigate("landing")}>← Back</button>
        </nav>
        <div className="practice-inner">
          <div className="step-header">
            <span className="tag tag-purple">Step 1 of 2</span>
            <h1>Choose a scenario</h1>
            <p>Pick the speaking situation you want to practice today.</p>
          </div>
          <div className="scenario-grid">
            {SCENARIOS.map((s) => (
              <button key={s.id} className="scenario-card card" onClick={() => setScenario(s)}>
                <span className="sc-emoji">{s.emoji}</span>
                <span className="sc-label">{s.label}</span>
                <span className="sc-hint">{s.hint}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // ── RECORDING ─────────────────────────────────────
  return (
    <div className="practice-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <button className="btn btn-ghost" onClick={() => setScenario(null)}>← Change Scenario</button>
      </nav>

      <div className="practice-inner">
        <div className="step-header">
          <span className="tag tag-purple">Step 2 of 2</span>
          <h1>Record your speech</h1>
          <p>
            <span className="scenario-badge">{scenario.emoji} {scenario.label}</span>
          </p>
        </div>

        <div className="record-area card">
          {/* Timer */}
          <div className="timer">{fmt(isRecording ? elapsed : duration)}</div>

          {/* Waveform while recording */}
          {isRecording && (
            <div className="waveform">
              {[...Array(7)].map((_, i) => <div key={i} className="waveform-bar" />)}
            </div>
          )}

          {/* Status text */}
          <p className="record-status">
            {!isRecording && !audioBlob && "Press the button to start recording"}
            {isRecording && "Recording… speak clearly into your microphone"}
            {!isRecording && audioBlob && `Recording ready · ${fmt(duration)}`}
          </p>

          {error && <p className="record-error">⚠️ {error}</p>}

          {/* Record button */}
          <button
            className={`record-btn ${isRecording ? "active" : "idle"}`}
            onClick={isRecording ? stopRecording : startRecording}
          >
            {isRecording
              ? <svg width="28" height="28" viewBox="0 0 28 28" fill="white"><rect x="6" y="6" width="16" height="16" rx="2"/></svg>
              : <svg width="28" height="28" viewBox="0 0 28 28" fill="white"><circle cx="14" cy="10" r="5"/><path d="M5 14a9 9 0 0018 0" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/><line x1="14" y1="23" x2="14" y2="26" stroke="white" strokeWidth="2" strokeLinecap="round"/></svg>
            }
          </button>
          <p className="record-btn-hint">{isRecording ? "Tap to stop" : "Tap to record"}</p>
        </div>

        {/* Tips */}
        <div className="tips-row">
          <div className="tip-item">💡 Speak at a comfortable pace (120–160 WPM is ideal)</div>
          <div className="tip-item">🎯 Avoid "uh", "um", "like" — pause instead</div>
          <div className="tip-item">⏱️ Aim for at least 30 seconds for better analysis</div>
        </div>

        {/* Analyze button */}
        {audioBlob && !isRecording && (
          <div className="analyze-row">
            <button className="btn btn-primary" onClick={handleAnalyze} style={{ fontSize: "16px", padding: "16px 40px" }}>
              ✨ Analyze My Speech
            </button>
            <button className="btn btn-ghost" onClick={() => { startRecording(); }}>
              🔄 Re-record
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
